import re
from collections import Counter
x=y=z=e=0.0; absE=False; cur=None
byz=Counter()
segs={}
with open('/app/text.gcode') as f:
    for line in f:
        s=line.strip()
        if s.startswith('M486'):
            m=re.match(r'M486 S(-?\d+)',s); 
            if m: cur=int(m.group(1))
            continue
        if s.startswith('M82'): absE=True; continue
        if s.startswith('M83'): absE=False; continue
        if s.startswith('G92'):
            m=re.search(r'E(-?[\d.]+)',s)
            if m: e=float(m.group(1))
            continue
        if s[:2] in ('G1','G0'):
            nx,ny,nz=x,y,z; de=0.0; hasE=False
            for tok in s.split():
                if not tok: continue
                c=tok[0]
                try:v=float(tok[1:])
                except:continue
                if c=='X':nx=v
                elif c=='Y':ny=v
                elif c=='Z':nz=v
                elif c=='E':
                    hasE=True
                    de=(v-e) if absE else v
                    if absE:e=v
            if hasE and de>0 and (nx!=x or ny!=y) and cur==0:
                zr=round(z,2)
                byz[zr]+=1
                segs.setdefault(zr,[]).append((x,y,nx,ny))
            x,y,z=nx,ny,nz
for k in sorted(byz): print(k,byz[k])
import pickle; pickle.dump(segs,open('/tmp/segz.pkl','wb'))
EOF
